import boto3

# Define a shared IAM role for all Lambda functions to use
iam_role = {
    "RoleName": "MyLambdaFunctionsRole",
    "AssumeRolePolicyDocument": {
        "Version": "2012-10-17",
        "Statement": [
            {
                "Effect": "Allow",
                "Principal": {
                    "Service": "lambda.amazonaws.com"
                },
                "Action": "sts:AssumeRole"
            }
        ]
    },
    "Policies": [
        {
            "PolicyName": "MyLambdaFunctionsPolicy",
            "PolicyDocument": {
                "Version": "2012-10-17",
                "Statement": [
                    {
                        "Effect": "Allow",
                        "Action": [
                            "s3:*",
                            "dynamodb:*",
                            "sns:*",
                            "sqs:*"
                        ],
                        "Resource": "*"
                    }
                ]
            }
        }
    ]
}

# Create the IAM role in AWS
iam_client = boto3.client('iam')
response = iam_client.create_role(RoleName=iam_role['RoleName'], AssumeRolePolicyDocument=json.dumps(iam_role['AssumeRolePolicyDocument']))

# Attach the policy to the role
policy_arn = response['Role']['Arn'] + ":policy/MyLambdaFunctionsPolicy"
response = iam_client.attach_role_policy(RoleName=iam_role['RoleName'], PolicyArn=policy_arn)